updateNodes.newJsCode:
// ============================================================================
// Format Evidence Comment - SYNCED from Runner status.json
// Reads actual runner evidence via SSH stdout, NOT stale RUN_INPUT.json
// Fallback chain: status.json → SSH raw output → prepData → hardcoded defaults
// ============================================================================

const prepData = $('Prepare RUN_INPUT.json').first().json;
const sshOutput = $input.first().json;

// → Extract evidence path →
const runId = prepData.run_id || 'unknown';
const evidenceDir = prepData.evidence_dir || '/opt/dev-fabric/evidence/github-agent-runs/' + prepData.owner + '/' + prepData.repo + '/issue-' + prepData.issue_number + '/' + runId + '/';

// → Defaults (Priority 3: last resort) →
let status = 'UNKNOWN';
let effectiveMode = prepData.mode || 'manual-terminal';
let providerConfigured = null;
let provider = null;
let model = null;
let openCodeVersion = null;
let evidenceSource = 'fallback (RUN_INPUT.json)';
let exitCodeInfo = 'unknown';

// → Priority 1: Parse status.json from SSH stdout →
let statusData = null;
if (sshOutput && sshOutput.stdout && typeof sshOutput.stdout === 'string') {
  try {
    statusData = JSON.parse(sshOutput.stdout);
  } catch (e) {
    // stdout is not valid JSON - will use fallback
  }
}

if (statusData) {
  evidenceSource = 'status.json';

  // Extract real values from status.json
  status = statusData.status || status;

  if (statusData.mode && statusData.mode.effective) {
    effectiveMode = statusData.mode.effective;
  }

  if (statusData.agent_runtime) {
    if (statusData.agent_runtime.opencode_provider_configured !== undefined) {
      providerConfigured = statusData.agent_runtime.opencode_provider_configured;
    }
    if (statusData.agent_runtime.opencode_version) {
      openCodeVersion = statusData.agent_runtime.opencode_version;
    }
  }

  if (statusData.provider) {
    provider = statusData.provider;
  }

  if (statusData.model) {
    model = statusData.model;
  }

  if (statusData.exit_code !== undefined) {
    exitCodeInfo = String(statusData.exit_code);
  } else if (sshOutput && sshOutput.exitCode !== undefined) {
    exitCodeInfo = String(sshOutput.exitCode);
  }

} else if (sshOutput && sshOutput.stdout) {
  // Priority 2: SSH output available but not parseable JSON
  evidenceSource = 'fallback (SSH raw)';
  if (typeof sshOutput.exitCode !== 'undefined') {
    exitCodeInfo = String(sshOutput.exitCode);
  }
}

// → Fill missing fields with sensible defaults →
if (providerConfigured === null) providerConfigured = false;
if (provider === null) provider = (effectiveMode === 'opencode-run') ? 'deepseek' : 'none';
if (model === null) model = (effectiveMode === 'opencode-run') ? 'deepseek-v4-pro' : 'none';
if (openCodeVersion === null) openCodeVersion = 'unknown';

// → Format comment body →
const commentBody = '## Runner Result\n' +
  '\n' +
  'Status: ' + status + '\n' +
  'Mode: ' + effectiveMode + '\n' +
  'Provider configured: ' + providerConfigured + '\n' +
  'Provider: ' + provider + '\n' +
  'Model: ' + model + '\n' +
  'OpenCode: ' + openCodeVersion + '\n' +
  '\n' +
  'Evidence: ' + evidenceDir + '\n' +
  '\n' +
  'Safety:\n' +
  '- No secrets emitted\n' +
  '- No auto-merge\n' +
  '- No GitHub Actions\n' +
  '\n' +
  '---\n' +
  'Evidence source: ' + evidenceSource;

return [{
  json: {
    owner: prepData.owner,
    repo: prepData.repo,
    issue_number: prepData.issue_number,
    issue_url: prepData.issue_url,
    run_id: runId,
    status: status,
    mode: effectiveMode,
    evidence_dir: evidenceDir,
    comment_body: commentBody,
    evidence_source: evidenceSource
  }
}];

// ============================================================================
// Final Result / Log Output - synced from status.json
// ============================================================================

const prepData = $('Prepare RUN_INPUT.json').first().json;
const evidenceFormat = $('Format Evidence Comment').first().json;

const result = {
  status: evidenceFormat.status || 'GREEN_PARTIAL_PLUS',
  issue_number: prepData.issue_number,
  issue_url: prepData.issue_url,
  run_id: prepData.run_id,
  evidence_dir: prepData.evidence_dir,
  dispatch_mode: evidenceFormat.mode || 'manual-terminal',
  evidence_source: evidenceFormat.evidence_source || 'fallback',
  guardrail_passed: true,
  labels_updated: true,
  comment_posted: true,
  next_action: 'Issue remains open. Human review required. Labels: agent:needs-review + evidence:attached set. OpenCode Provider/Auth + Hermes continue pending.'
};

return [{ json: result }];
